INSERT INTO `issue_logs` VALUES (11,'ISS20260401053310','家浩更新解决','朱家浩','2026-04-01 05:34:57',NULL,'2026-04-01 05:34:57','2026-04-01 05:34:57'),(12,'ISS20260320095332','屏蔽掉了一个进车传感器','杜林','2026-04-01 08:51:08',NULL,'2026-04-01 08:51:08','2026-04-01 08:51:08'),(13,'ISS20260407095828','算法优化更新，后续再看订单的结果','家浩','2026-04-07 10:01:02',NULL,'2026-04-07 10:01:02','2026-04-07 10:01:02'),(14,'ISS20260408033225','可视化显示设备一直处于自检中， 下位机日志显示： Cemera error 后经家浩查看， 是相机的IP变了经重新设置IP后设备恢复正常','韩凯征','2026-04-08 03:36:15',NULL,'2026-04-08 03:36:15','2026-04-08 03:36:15'),(15,'ISS20260326051614','家浩反馈有一版修复了ftp文件问题的。跟这个表征一样，更新之后继续观察','家浩','2026-04-08 09:02:59',NULL,'2026-04-08 09:02:59','2026-04-08 09:02:59'),(16,'ISS20260414073930','更换小电脑','韩凯征','2026-04-14 07:40:31',NULL,'2026-04-14 07:40:31','2026-04-14 07:40:31'),(17,'ISS20260414083142','把电池装上（空运把纽扣电池给抠下来了，然后导致b iOS设置丢失）','韩凯征','2026-04-14 08:39:07',NULL,'2026-04-14 08:39:07','2026-04-14 08:39:07'),(18,'ISS20260414083142','让客户进入BIO, 修改BIOS的相关内容。 进入BIOS的内容方法如下： \n1、有线键盘，接ps/2旁边的usb口\n2、按电脑power键开启服务器\n3、等到键盘灯亮起时，连续多次按delete键','韩凯征','2026-04-17 02:40:00','[{\"url\": \"http://els-pub-04.oss-cn-shanghai.aliyuncs.com/static/After-sales%20management%20system/devices/DE-CSI-F22011010631DE0050-20260228000128-DEU-%E9%BE%99%E9%97%A8%E7%89%88%E5%85%A8%E8%BD%A6360%C2%B0%E8%A1%A8%E9%9D%A2%E7%BC%BA%E9%99%B7AI%E6%A3%80%E6%B5%8B%E8%AE%BE%E5%A4%87-DO/issues/ISS20260414083142/logs/1776393599529_%E5%BE%AE%E4%BF%A1%E8%A7%86%E9%A2%912026-04-17_103829_586.mp4?OSSAccessKeyId=LTAI5tBEhp9PtWYsYHmGJY1w&Expires=1776998400&Signature=7%2Bd%2BjfplKKy4sI3UGE%2FiofSqAEY%3D&response-content-disposition=attachment%3B%20filename*%3DUTF-8\'\'%25E5%25BE%25AE%25E4%25BF%25A1%25E8%25A7%2586%25E9%25A2%25912026-04-17_103829_586.mp4\", \"name\": \"微信视频2026-04-17_103829_586.mp4\", \"size\": 1479341, \"ossPath\": \"oss://els-pub-04/static/After-sales management system/devices/DE-CSI-F22011010631DE0050-20260228000128-DEU-龙门版全车360°表面缺陷AI检测设备-DO/issues/ISS20260414083142/logs/177639359952