/*!40000 ALTER TABLE `kb_articles` DISABLE KEYS */;
INSERT INTO `kb_articles` VALUES (1,'龙门自检不过','龙门一直闪黄灯，不能正常进入等车流程，查看日志，显示自检不过，文件上传失败','由于旧程序bug，导致文件符开启过多超过系统默认限制','1.紧急需要演示或者客户有迫切的过车请求——直接重启设备\n2.不紧急可给时间处理——联系开发人员对程序进行版本更新，目前已有修复此问题的程序版本','视觉',7,'[\"闪黄灯\", \"自检不过\", \"龙门\"]',0,5,0,NULL,'2026-04-08 14:49:07','2026-05-18 03:18:04',NULL),(2,'底盘不工作，过车没有反应','底盘指示灯一直没有变绿，或者多合一进行扫描的时候底盘不工作','相机断联 或者 在自检过程中','1.如果进入下位机查看日志，发现找不到相机，就是相机自身问题，可进入MVS查看相机状态是否正常，目前发现有偶发的丢ip绑定的情况，此时需要重新绑定相机ip，后对下位机采图服务进行重启；\n2.如果是刚开机的时候，可能是底盘的自检还没通过，目前自检时间时长时短，与下位机PLC交互有关系，这种情况等待就好，一般是PLC最多给到第三次自检信号，自检可通过。','视觉',6,'[\"底盘\", \"黄灯\"]',0,5,0,NULL,'2026-04-08 14:54:09','2026-05-18 03:28:53',NULL),(3,'龙门报警-相机断联','上位机软件出现报警：相机断联','因为网口不稳定导致','1.进入下位机命令操作页面，使用ifconfig检查各个网口状态，找到应该识别到相机ip，但没有识别到网口；然后使用 “ifconfig 网口名 down” 及 “ifconfig 网口名 up” 进行网口重启操作，可以恢复正常；\n2.联系视觉开发工程师，目前该问题最新版本程序已经融入自动化解决功能。','视觉',7,'[\"相机\", \"断联\", \"下位机\"]',0,2,0,NULL,'2026-04-24 02:45:40','2026-04-27 05:36:47','[{\"url\": \"http://els-pub-04.oss-cn-shanghai.aliyuncs.com/static/After-sales%20management%20system/knowledge-base/3/1777268177378_dac94179816332476bd0f13b28359f11.png?OSSAccessKeyId=LTAI5tBEhp9PtWYsYHmGJY1w&Expires=1777873007&Signature=j2sB7%2F1F2igdxiv6W0rJUZ9YoJM%3D&response-content-disposition=attachment%3B%20filename*%3DUTF-8\'\'dac94179816332476bd0f13b28359f11.png\", \"name\": \"dac94179816332476bd0f13b28359f11.png\", \"size\": 27530, \"ossPath\": \"oss://els-pub-04/static/After-sales management system/knowledge-base/3/1777268177378_dac94179816332476bd0f13b28359f11.png\"}, {\"url\": \"http://els-pub-04.oss-cn-shanghai.aliyuncs.com/static/After-sales%20management%20system/knowledge-base/3/1777268195614_cd685e26bf2b516c580f03c4aa1ac74a.jpg?OSSAccessKeyId=LTAI5tBEhp9PtWYsYHmGJY1w&Expires=1777873007&Signature=iyXPnwDXjpaXFZiOgzgAD5dSkxU%3D&response-content-disposition=attachment%3B%20filename*%3DUTF-8\'\'cd685e26bf2b516c580f03c4aa1ac74a.jpg\", \"name\": \"cd685e26bf2b516c580f03c4aa1ac74a.jpg\", \"size\": 1359254, \"ossPath\": \"oss://els-pub-04/static/After-sales management system/knowledge-base/3/1777268195614_cd685e26bf2b516c580f03c4aa1ac74a.jpg\"}]'),(4,'基础版大盒子---STO报警','可视化不能操作转盘转动，显示转盘电机故障，STO报警','急停开关被按下，或者其他报警导致','1.先松开急停开关\n2.可视化Alarm界面短按“RESET”或者短按操作台复位按钮\n3.可视化进入Debug，点“manual”按钮显示蓝色，使能手动操作\n4.按转盘FWD或REV按钮看转盘是否正常转动，如果正常转动，完毕\n5.上一步如果不正常，请接着到主电柜，打开柜门，看驱动器上的STO是否消失\n6.如果未消失，请将断路器Q5关断，等待10秒\n7.再次将Q5合闸，观察驱动器是否不再显示STO报警，如果是，尝试步骤4','电气',4,'[\"STO\", \"报警\"]',0,3,0,NULL,'2026-05-18 03:13:50','2026-05-18 03:22:47','[{\"url\": \"http://els-pub-04.oss-cn-shanghai.aliyuncs.com/static/After-sales%20management%20system/knowledge-base/4/1779073992991_K32STO.png?OSSAccessKeyId=LTAI5tBEhp9PtWYsYHmGJY1w&Expires=1779678831&Signature=l5yGWqAffbV1ZIGF%2BSIwImNXsZ4%3D&response-content-disposition=attachment%3B%20filename%3D%22K32STO.png%22%3B%20filename*%3DUTF-8\'\'K32STO.png\", \"name\": \"K32STO.png\", \"size\": 732916, \"ossPath\": \"oss://els-pub-04/static/After-sales management system/knowledge-base/4/1779073992991_K32STO.png\"}, {\"url\": \"http://els-pub-04.oss-cn-shanghai.aliyuncs.com/static/After-sales%20management%20system/knowledge-base/4/1779073993376_%E7%94%B5%E6%9F%9C.png?OSSAccessKeyId=LTAI5tBEhp9PtWYsYHmGJY1w&Expires=1779678831&Signature=tNgDRiBntkl40SG%2FMW%2BlLfaeNXI%3D&response-content-disposition=attachment%3B%20filename%3D%22__.png%22%3B%20filename*%3DUTF-8\'\'%25E7%2594%25B5%25E6%259F%259C.png\", \"name\": \"电柜.png\", \"size\": 718301, \"ossPath\": \"oss://els-pub-04/static/After-sales management system/knowledge-base/4/1779073993376_电柜.png\"}, {\"url\": \"http://els-pub-04.oss-cn-shanghai.aliyuncs.com/static/After-sales%20management%20system/knowledge-base/4/1779073993469_%E5%A4%8D%E4%BD%8D.png?OSSAccessKeyId=LTAI5tBEhp9PtWYsYHmGJY1w&Expires=1779678831&Signature=8%2BtRxrt8NhG%2F78kOg9LlKptIQ1M%3D&response-content-disposition=attachment%3B%20filename%3D%22__.png%22%3B%20filename*%3DUTF-8\'\'%25E5%25A4%258D%25E4%25BD%258D.png\", \"name\": \"复位.png\", \"size\": 14464, \"ossPath\": \"oss://els-pub-04/static/After-sales management system/knowledge-base/4/1779073993469_复位.png\"}, {\"url\": \"http://els-pub-04.oss-cn-shanghai.aliyuncs.com/static/After-sales%20management%20system/knowledge-base/4/1779073993535_%E8%BD%AC%E7%9B%98DEBUG.png?OSSAccessKeyId=LTAI5tBEhp9PtWYsYHmGJY1w&Expires=1779678831&Signature=NhV5t%2Fc4xpfg2w0d99Ru4ojO930%3D&response-content-disposition=attachment%3B%20filename%3D%22__DEBUG.png%22%3B%20filename*%3DUTF-8\'\'%25E8%25BD%25AC%25E7%259B%2598DEBUG.png\", \"name\": \"转盘DEBUG.png\", \"size\": 49202, \"ossPath\": \"oss://els-pub-04/static/After-sales management system/knowledge-base/4/1779073993535_转盘DEBUG.png\"}]');
