INSERT INTO `version_releases` VALUES (12,910105,'v1.0.10','高配版底盘视觉控制部署程序-适用于埋地与非埋地','【新增功能】\n相对于以往版本加入图像锐化功能，使得输出图像更为清晰','汽车底盘检测设备','2026-02-28','manual','2026-03-02 05:56:20','2026-04-18 01:58:14'),(14,910105,'v1.0.5','高配版侧扫视觉控制部署程序','【新增功能】\n将上传重试次数提出配置文件','轮胎侧面检测设备','2026-02-26','manual','2026-03-02 06:20:33','2026-04-18 01:58:40'),(15,910105,'v1.0.0','视觉控制程序加密','为了对设备的程序进行运行时加密','基础程序','2026-02-28','manual','2026-03-02 07:18:28','2026-03-03 09:17:07'),(16,910105,'DS-v3.1.7','DS3.2版本龙门视觉控制程序','【Bug修复】\n修复ftp链路正常但自检不通过问题，根源是文件打开太多关闭异常，从而超过系统限制。\n解决办法：增加更稳定的文件符清理机制，并扩大系统文件限制。','龙门版全车360°表面缺陷AI检测设备','2026-02-26','manual','2026-03-03 08:42:41','2026-04-18 01:57:26'),(19,490266,'V3.5.32','龙门上位机软件','-新增罗马尼亚语翻译','龙门版全车360°表面缺陷AI检测设备','2026-03-02','manual','2026-03-03 09:33:42','2026-03-11 10:21:36'),(20,490266,'V3.15.6','高配底盘上位机软件','- 合并标准底盘和高配底盘为一套程序\n- 修复已知界面Bug\n- 优化部分UI','汽车底盘检测设备','2026-03-11','manual','2026-03-03 09:34:52','2026-03-11 10:35:09'),(21,490266,'V3.10.4','轿车胎纹上位机软件','- 增加PDF报告自动打印功能\n- 修复车牌绑定不稳定的情况','汽车胎纹检测设备','2026-03-01','manual','2026-03-03 09:36:02','2026-03-24 10:05:43'),(22,490266,'V1.5.2','轮胎侧扫上位机软件','新增：\n- PDF报告自动生成功能\n修复：\n- 报告Logo无法自定义的bug','轮胎侧面检测设备','2026-03-02','manual','2026-03-03 09:37:16','2026-03-11 08:46:29'),(23,490266,'V1.5.18','标准底盘上位机软件','新增：通过软件动态调整相机曝光\n','汽车底盘检测设备','2026-03-02','manual','2026-03-03 09:38:34','2026-03-11 10:28:03'),(24,490266,'V2.0.7','摄影棚海外版','针对海外用户开发的全新摄影棚版本。\n功能：\n- 关门外观拍照、开门外观拍照、内饰拍照\n- 本地创建订单，可任意搭配检测项\n- 支持数据本地对接\n- 用户界面和后端服务集成为一个程序','天眼云数字化车辆检测设备','2026-03-02','manual','2026-03-03 09:39:44','2026-03-11 10:25:50'),(25,490266,'V1.1.2','Windows托盘程序','- 新增上位机Windows服务监控\n- 新增上位机错误日志扫描功能\n- 新增邮件发送功能','系统辅助','2026-03-02','manual','2026-03-03 09:41:23','2026-03-11 08:35:53'),(26,713028,'V3.5.12','DO龙门服务器部署程序','1. 升级：龙门版本迭代（新增镜像），兼容新显卡5090D\n2. DO模型迭代: M1.7-do260212\n3. Bug修复：异常关机时，偶发幽灵容器','龙门版全车360°表面缺陷AI检测设备','2026-03-05','manual','2026-03-06 01:46:50','2026-03-06 01:46:50'),(27,713028,'V3.5.11','DS三合一龙门服务器部署程序','1. 三合一龙门程序包含：DS龙门程序、侧扫程序、底盘程序\n2. 升级：龙门版本迭代（新增镜像）、侧扫版本迭代（新增镜像），兼容新显卡5090D\n3. DS模型: M1.8-ds260218\n4. Bug修复：异常关机时，偶发幽灵容器','龙门版全车360°表面缺陷AI检测设备','2026-03-04','manual','2026-03-06 01:54:16','2026-04-09 05:31:31'),(28,713028,'V1.0.5','侧扫服务器部署程序','1. 版本优化，使运行更稳定','轮胎侧面检测设备','2025-09-21','manual','2026-03-06 01:56:00','2026-03-06 01:56:58'),(29,713028,'V2.1.1','底盘服务器部署程序-CPU版本','更新内容：\n新增chassis_main.ini 配置文件。\n将ip和端口号等写到配置文件中\n兼容cpu和gpu推理\nmodel:CD250319_0.3\n','汽车底盘检测设备','2025-08-21','manual','2026-03-06 01:58:56','2026-03-20 07:24:27'),(30,752682,'PLC:V1.0.0','DIA-PV-C,标准龙门，轿车','首台PRO版标准龙门，台州测试','龙门版全车360°表面缺陷AI检测设备','2023-03-08','manual','2026-03-06 03:12:19','2026-05-11 07:57:41'),(31,752682,'PLC:V2.0.0','DIA-PV-C,标准龙门，轿车','中海龙版本，首台PRO版（台州测试）基础上更改','龙门版全车360°表面缺陷AI检测设备','2023-06-03','manual','2026-03-06 05:20:28','2026-05-11 07:57:03'),(32,752682,'PLC:V2.0.3','DIA-PV-C,标准龙门，轿车','多对射传感器版本，增加可视化','龙门版全车360°表面缺陷AI检测设备','2025-08-24','manual','2026-03-06 05:24:53','2026-05-11 07:58:10'),(33,752682,'PLC:V3.0.2','DIA-PV-C,标准龙门，轿车','去掉多对射传感器，增加一组北醒激光雷达','龙门版全车360°表面缺陷AI检测设备','2025-09-15','manual','2026-03-06 05:30:28','2026-05-11 07:57:29'),(34,752682,'PLC:V1.0.0','DIA-PV-D，冰雹龙门，DO','为首版DO龙门','龙门版全车360°表面缺陷AI检测设备','2024-09-16','manual','2026-03-06 05:37:53','2026-05-11 07:58:17'),(35,752682,'PLC:V2.0.0','DIA-PV-D，冰雹龙门，DO','早期版本，bs10和bs11两个信号是开始拍照信号，加长加高龙门用；增加流程显示程序，内容显示在交互界面','龙门版全车360°表面缺陷AI检测设备','2025-04-07','manual','2026-03-06 05:45:22','2026-05-11 07:57:35'),(36,752682,'PLC:V2.0.1','DIA-PV-D，冰雹龙门，DO','测量光幕通讯数据读取，测量光幕高度数据应用','龙门版全车360°表面缺陷AI检测设备','2025-07-25','manual','2026-03-06 05:48:30','2026-05-11 07:56:52'),(37,752682,'PLC:V2.0.2','DIA-PV-D，冰雹龙门，DO','新的版本bs10和bs11这两个信号是出车，另外增加了bs15和bs16作为拍照；有可视化监控；修复传感器报警的BUG，增加手动调试功能、流程显示程序；添加结构光手动通断电操作','龙门版全车360°表面缺陷AI检测设备','2025-10-21','manual','2026-03-06 05:51:14','2026-05-11 07:56:36'),(38,752682,'PLC:V3.0.2','TSD-CV-LG-2010/TSD-CV-UG-2010 ,驶过式轿车胎纹','增加可视化IO监控、增加手动调试程序、增加流程信息显示程序 ，优化可视化内容','汽车胎纹检测设备','2025-09-15','manual','2026-03-06 06:00:31','2026-05-11 08:00:52'),(39,910105,'DO-v1.7.7','DO版本龙门视觉控制程序','Update version to 1.7.7 and enhance resource management\nUpdated version string from 1.7.6 to 1.7.7 in as.cpp.\nAdded code to raise the open-file-descriptor soft limit in main function to prevent file descriptor exhaustion.\nEnsured proper cleanup of CURL resources in filectl.cpp and flowctl.cpp to prevent memory leaks and dangling pointers.\nAdded curl_easy_cleanup calls in various error handling paths to ensure resources are released appropriately.','龙门版全车360°表面缺陷AI检测设备','2026-03-02','manual','2026-03-06 06:03:06','2026-04-18 01:57:21'),(40,752682,'PLC:V2.0.0','CSD-PV-2012/CSD-PV-UG-2201','第一代PCB使用程序,内部使用电路板，进车感应器，X4 X5在内部电路并连使用，开始拍照，与结束拍照也是并联使用','汽车底盘检测设备','2022-10-23','manual','2026-03-06 06:10:31','2026-05-11 07:59:40'),(41,752682,'PLC:V3.0.0','CSD-PV-2012/CSD-PV-UG-2201','第二代电路板，进车感应器，X4，X5在内部电路独立使用 ，开始拍照，与结束拍照也是独立使用\n；更新误触发后逻辑，不再进入自检流程，缩短再次进车时间、等待图片上传与上位机通讯后处理','汽车底盘检测设备','2025-04-06','manual','2026-03-06 06:14:24','2026-05-11 07:59:25'),(42,752682,'PLC:V4.0.0','CSD-PV-2012/CSD-PV-UG-2201，高配底盘','第三版PCB，LED控制由开机常亮变成常灭，进车方向右侧三组传感器改为TTL通讯，通过接收距离和强度数据判断是否感应；增加流程显示程序，内容由触摸屏界面显示到上位机；增加手动调试程序；\n增加处理读取的传感器数据，逻辑中剔除不连续出现的异常数据；同组传感器功能并用，只要有大于等于一个传感器正常，就让它正常过车','汽车底盘检测设备','2025-09-15','manual','2026-03-06 06:19:31','2026-05-11 07:59:48'),(45,752682,'PLC:V1.0.0','TSS-PV-2403，侧面扫描','首版','轮胎侧面检测设备','2024-03-10','manual','2026-03-06 06:40:21','2026-05-11 08:01:10'),(46,752682,'PLC:V1.0.1','TSS-PV-2403，侧面扫描','增加流程打印信息，修改流程为英文，增加可视化，手动调试程序、流程显示程序','轮胎侧面检测设备','2025-09-16','manual','2026-03-06 06:41:55','2026-05-11 08:01:21'),(47,752682,'PLC:V1.0.2','TSS-PV-2403，侧面扫描','01增加急停开关信号X11，版本升级为V1.0.2,向下兼容（低版本可以升级为高版本，高版本包容了低版本的功能并有所改进）\n02修复出车信号定时器T204在慢速出车的时候自动复位，导致出车条件不满足的情况（改为出车后靠流程复位\n）','轮胎侧面检测设备','2025-12-09','manual','2026-03-06 06:43:03','2026-05-11 08:01:17'),(49,752682,'PLC:V2.0.0','DIS-PV-2302，基础版','转盘驱动方案由6个直流电机外圆摩擦传动更改为4个交流电机变频传动；硬件电路更改，增加可视化','天眼云数字化车辆检测设备','2026-01-12','manual','2026-03-06 07:21:46','2026-05-11 08:01:34'),(50,752682,'PLC:V1.0.0','DIS-PV-2302，基础版','优化版V2.0.0版本拷贝程序，在此基础上更改，转盘传动方案仍然为6个直流电机，去掉底盘模组','天眼云数字化车辆检测设备','2023-05-27','manual','2026-03-06 07:24:55','2026-05-11 08:01:45'),(51,910105,'MV-CL042-91GC-config-1.0.0','高配底盘相机配置文件','','基础程序','2026-03-04','manual','2026-03-06 09:01:42','2026-03-10 03:17:04'),(52,910105,'v1.1.1','高配底盘视觉控制部署程序-适用于埋地与非埋地底盘','【增加功能】\n增加通过http的曝光参数选择','汽车底盘检测设备','2026-03-10','manual','2026-03-12 05:42:10','2026-04-18 01:58:04'),(53,752682,'PLC:V2.0.3','DIA-PV-D，冰雹龙门，DO','01将设备指示灯的颜色指示状态转化成不同的值，通过地址间接传递给上位机\n02反向误触发恢复预留2秒，降低反向通过的误触发几率\n03门框左右感应器增加感应同步时间误差允许程序，在300ms时间内认为同步\n04程序增加门框感应器并连使用和串联使用选择功能,可视化增加选择按钮','龙门版全车360°表面缺陷AI检测设备','2026-03-08','manual','2026-03-12 05:46:36','2026-05-11 07:58:05'),(54,752682,'PLC:V3.0.3','DIA-PV-C,标准龙门，轿车','01将设备指示灯的颜色指示状态转化成不同的值，通过地址间接传递给上位机\n02反向误触发恢复预留2秒，降低反向通过的误触发几率\n03门框左右感应器增加感应同步时间误差允许程序，在300ms时间内认为同步\n04程序增加门框感应器并连使用和串联使用选择功能,可视化增加选择按钮\n05出车后逻辑优化，PC错误返回自检；超时不自检，直接返回等车状态','龙门版全车360°表面缺陷AI检测设备','2026-03-11','manual','2026-03-16 06:01:57','2026-05-11 07:57:16'),(55,752682,'PLC:V4.0.1','CSD-PV-2012/CSD-PV-UG-2201，高配底盘','01将老版本（打光控制电阻控制模式）与新版本（打光控制电压控制模式）进行整合，使程序兼容新老版本\n02升级可视化，增加两个设置开关（LED高亮度常开常闭开关和传感器IO模式与数据模式切换开关），结合PLC程序，兼容老版本版本\n03修复Y10打光IO模式和数据模式切换的时候，导致SFC流程不运行的情况，系编程软件自身BUG或者PLC本身问题，已通过增加step（Initial2）步避免此问题\n04出车传感器设置100ms抗干扰时间，一定程度稳定过车过程','汽车底盘检测设备','2026-03-14','manual','2026-03-16 07:52:23','2026-05-11 07:59:33'),(56,910105,'DO-v1.7.8','DO版本龙门视觉控制程序','Update version to 1.7.8 and refactor auto car model handling\n- Removed the global variable `g_autoCarModel` and its associated logic from `asstart.cpp`.\n- Updated `as.cpp` to reflect the new version number.\n- Modified `mbcommu.cpp` to use `g_Car` instead of `g_autoCarModel` for camera selection logic.\n- Adjusted camera selection logic in `ordproc_continuous.cpp` to account for sensor availability.\n- Cleaned up unnecessary code related to `g_autoCarModel` in multiple files.','龙门版全车360°表面缺陷AI检测设备','2026-03-15','manual','2026-03-17 02:18:35','2026-04-18 01:57:16'),(57,910105,'v3.0.7','胎纹扫描视觉控制程序','【优化改进】\n加长重试超时时间','汽车胎纹检测设备','2026-03-16','manual','2026-03-17 09:53:35','2026-04-18 01:58:35'),(58,490266,'V1.5.7','大车胎纹上位机软件','兼容最新DeviceHub和Perpheral，自持通过ElsAdmin部署。\n新增：\n- PDF报告\n- 关键信息复制\n- 关键词搜索','汽车胎纹检测设备','2026-03-18','manual','2026-03-18 04:23:17','2026-03-18 04:23:17'),(59,910105,'DS3.2-v3.1.8','DS3.2版本龙门视觉控制程序','Update version to 3.1.8 and refactor camera selection logic\n- Updated version string in as.cpp from 3.1.7 to 3.1.8.\n- Removed unused global variable g_autoCarModel from asstart.h and asstart.cpp.\n- Refactored camera selection logic in mbcommu.cpp to improve clarity and maintainability.\n- Adjusted logging statements in asstart.cpp for consistency and readability.\n- Modified img_all_save_upload_for_camera_sl function in ordproc_sl.cpp to handle sensor availability more effectively.\n- Removed the getCarInfoLoop function as it is no longer needed.\n- Cleaned up binary files in the build directory.','龙门版全车360°表面缺陷AI检测设备','2026-03-18','manual','2026-03-20 06:37:45','2026-04-18 01:57:10'),(60,713028,'V1.1.0','侧扫服务器部署程序','tireOCR v1.2.0\n更新内容：\n1. bug修复，main.py 228行，输入信息info不用去重。\n2. 品牌库更新\n3. 日期解析优化：使用边界感知正则，排除长数字串中的误匹配；增加年份下限(≥2010)','轮胎侧面检测设备','2026-03-13','manual','2026-03-20 07:26:44','2026-03-20 07:26:44'),(61,713028,'V3.2.2','SE多合一龙门服务器部署程序','1. SE龙门（按部位展示）多合一设备，适配5090D显卡\n2. seg模型迭代，车门分上下，增加后视镜识别','龙门版全车360°表面缺陷AI检测设备','2026-04-02','manual','2026-03-20 07:31:05','2026-04-09 05:12:07'),(62,490266,'V3.16.2','高配底盘上位机软件','新增日文翻译','汽车底盘检测设备','2026-03-23','manual','2026-03-24 10:04:07','2026-03-24 10:04:27'),(63,490266,'V3.14.1','轿车胎纹上位机软件','新增日语翻译','汽车胎纹检测设备','2026-03-24','manual','2026-03-24 10:05:21','2026-03-24 10:05:21'),(64,490266,'V2.0.8','摄影棚海外版','修复内饰相机重试无反应的bug\n增加内饰相机模拟器\n其它细节问题调整','天眼云数字化车辆检测设备','2026-03-24','manual','2026-03-24 10:07:25','2026-03-24 10:07:25'),(65,490266,'V1.7.2','轮胎侧扫上位机软件','新增日语翻译',NULL,'2026-03-24','manual','2026-03-24 10:08:37','2026-03-24 10:08:37'),(66,490266,'V3.6.7','龙门上位机软件','新增斯洛文尼亚语、日语\n新增对接模式（从客户推送的进车列表匹配车辆）','龙门版全车360°表面缺陷AI检测设备','2026-03-23','manual','2026-03-25 01:47:40','2026-03-25 01:48:27'),(67,490266,'v1.7.2','轮胎侧扫上位机软件','新增日语翻译','轮胎侧面检测设备','2026-03-25','manual','2026-03-25 01:49:46','2026-03-25 01:49:46'),(68,910105,'SE-v2.0.2','SE版龙门视觉控制程序','Update project files and improve FTP handling\n- Updated cmake install script path for development environment.\n- Modified AlarmQue to use wait_for for better responsiveness.\n- Introduced FTPSession class for reusable FTP sessions to optimize file uploads.\n- Changed global boolean flags to atomic for thread safety in gpioctl and parload.\n- Bumped version number to 2.0.2 in as.cpp.\n- Enhanced error handling in redis communication functions.\n- Improved file upload error handling in filectl.\n- Added cleanup for curl handles in flowctl to prevent memory leaks.\n- Fixed memory management in modbustcp read function.\n- Refactored image upload logic in ordproc_continuous to utilize FTPSession.\n- Updated parameter loading to use snprintf for safer string handling.','龙门版全车360°表面缺陷AI检测设备','2026-03-24','manual','2026-03-25 03:55:07','2026-04-18 01:57:02'),(69,752682,'PLC:V2.0.3','DIA-PV-E，轿车，SE龙门（4S龙门）','01与DO龙门通用，使用DO龙门V2.0.3程序，为SE的最初版本，\n02此版本为2026年3月26号发布，第一台出货设备开始使用','龙门版全车360°表面缺陷AI检测设备','2026-03-21','manual','2026-03-26 02:27:51','2026-05-11 07:57:52'),(70,490266,'v1.6.5','大车胎纹上位机软件','【bug修复】\n- 修复只有一个轮胎时显示不正确的问题\n- 修复从报告页返回时始终返回订单列表第一页的体验问题','汽车胎纹检测设备','2026-03-28','manual','2026-03-28 02:17:30','2026-03-28 02:17:30'),(71,713028,'V3.4.2','DO龙门服务器部署程序','硬件升级前DS版本（按部位展示）4090D显卡\n1. scratch和dent用两个表\n2. 追踪算法优化\n3. bug修复，尺寸表里没有front-door-upper等\n4. config.json   max_det 由500 调成1000\n5. derRT-M1.2 DO250930\n6. seg250829','龙门版全车360°表面缺陷AI检测设备','2025-10-27','manual','2026-04-03 01:37:16','2026-04-03 01:37:54'),(72,713028,'V3.5.15','DO龙门服务器部署程序','硬件升级前DO版本。适配4090D显卡,基于V3.5.13版本更新了sl置信度','龙门版全车360°表面缺陷AI检测设备','2026-04-02','manual','2026-